const SOLUTIONS={gc:{color:"#5b4fc7",title:"Your command center for every active project",desc:"General contractors get a full workspace for billing, RFIs, change orders, compliance, scheduling, and client communication — all in one place.",features:[{h:"AIA billing & draws",p:"Create G702/G703 draw requests, manage schedule of values, track retainage, and collect lien waivers — all audit-ready."},{h:"RFI & change order workflows",p:"Log, assign, and track every field question and scope change with full history, attachments, and approval routing."},{h:"Subcontractor coordination",p:"Assign tasks, request uploads, track compliance, and message trades — without a single group text."}]},sub:{color:"#3d6b8e",title:"See your scope, do your work, stay compliant",desc:"Subcontractors get a focused workspace showing only what matters to them — tasks, documents, compliance, and communication with the GC.",features:[{h:"Today Board",p:"One screen showing all your open tasks, upload requests, and deadlines across every project you're on."},{h:"Compliance self-service",p:"Upload your insurance certs, licenses, and W-9s. See exactly what's expiring and when."},{h:"Scoped project access",p:"See your scope, your schedule, your documents — not the entire project. Clean and focused."}]},commercial:{color:"#3178b9",title:"Real-time visibility into your investment",desc:"Commercial property owners and tenant reps get a professional portal for approvals, financial tracking, and project transparency.",features:[{h:"Approval workflows",p:"Review change orders, procurement requests, and design decisions with full context and one-click response."},{h:"Draw review & payment history",p:"Full ledger of every draw request, payment, and lien waiver — with change order financial summaries."},{h:"Progress & documentation",p:"Photo updates, milestone tracking, and a curated document library — no noise, just what matters to you."}]},residential:{color:"#2a7f6f",title:"Your home build, demystified",desc:"Homeowners get a warm, clear portal to follow along with their build — from selections to photos to payments, in language that makes sense.",features:[{h:"Selections studio",p:"Browse curated options for countertops, flooring, fixtures — compare side-by-side, and see how each choice affects your budget."},{h:"Progress photos & updates",p:"See what's happening on site with photo timelines, builder notes, and milestone announcements — all in one feed."},{h:"Clear budget tracking",p:"Milestone-based payment timeline, selections impact on your total, and plain-English explanations of how payments work."}]}};

