const FAQ_THREADS=[{id:0,avatar:"HO",avatarColor:"#2a7f6f",name:"Sub & client pricing",preview:"Nope — always free",sub:"Thread with Homeowner",q:"Do my subs and clients need their own paid accounts?",a:"Nope. Subcontractor and client portal access is always free — they're included in your plan. You only pay based on your team size and project count. Everyone else gets in at no extra cost.",qTime:"Today, 9:14 AM",aTime:"Today, 9:16 AM"},{id:1,avatar:"GC",avatarColor:"#5b4fc7",name:"Switching plans",preview:"Upgrade anytime, pro-rated",sub:"Thread with GC",q:"We're growing fast. Can I switch plans as we scale?",a:"Absolutely. Upgrade or downgrade anytime. If you upgrade mid-cycle, you'll be prorated for the remainder. Downgrade takes effect at your next billing period.",qTime:"Today, 10:02 AM",aTime:"Today, 10:04 AM"},{id:2,avatar:"GC",avatarColor:"#5b4fc7",name:"Active project limits",preview:"Archived projects don't count",sub:"Thread with GC",q:"What counts as an \"active project\" for the Starter limit?",a:"Any project that isn't archived. Once a project is complete and you archive it, it no longer counts against your limit — and you can still access all its records anytime.",qTime:"Apr 12, 3:20 PM",aTime:"Apr 12, 3:22 PM"},{id:3,avatar:"CO",avatarColor:"#3178b9",name:"Data security & SSO",preview:"Encrypted, row-level isolated",sub:"Thread with Commercial Owner",q:"How secure is our project data? We have NDAs on everything.",a:"All data is encrypted at rest and in transit. We use row-level security so each organization's data is fully isolated. Enterprise plans also support SSO/SAML for your IT requirements.",qTime:"Apr 10, 2:45 PM",aTime:"Apr 10, 2:48 PM"},{id:4,avatar:"GC",avatarColor:"#5b4fc7",name:"QuickBooks integration",preview:"On the roadmap",sub:"Thread with GC",q:"We use QuickBooks. Any integrations coming?",a:"QuickBooks, Sage, and Xero integrations are on the roadmap and coming soon. Enterprise plans can access custom integration support today if you need it sooner.",qTime:"Apr 8, 11:30 AM",aTime:"Apr 8, 11:33 AM"}];

